  '[{"id":"party_a_email","token":"{{party_a_email}}","label":"Your Email","description":"Email address of the first party","category":"party_a","type":"email","required":true,"autofillKey":"email"},{"id":"party_a_name","token":"{{party_a_name}}","label":"Your Name","description":"Full legal name of the first party","category":"party_a","type":"text","required":true,"autofillKey":"name"},{"id":"party_a_address","token":"{{party_a_address}}","label":"Your Address","description":"Business or mailing address","category":"party_a","type":"textarea","required":false,"autofillKey":"address"},{"id":"party_a_company","token":"{{party_a_company}}","label":"Your Company","description":"Company or organization name","category":"party_a","type":"text","required":false,"autofillKey":"company_name"},{"id":"party_a_title","token":"{{party_a_title}}","label":"Your Title","description":"Job title or role","category":"party_a","type":"text","required":false,"autofillKey":"job_title"},{"id":"party_b_email","token":"{{party_b_email}}","label":"Other Party Email","description":"Email address of the second party","category":"party_b","type":"email","required":true},{"id":"party_b_name","token":"{{party_b_name}}","label":"Other Party Name","description":"Full legal name of the second party","category":"party_b","type":"text","required":true},{"id":"party_b_address","token":"{{party_b_address}}","label":"Other Party Address","description":"Business or mailing address","category":"party_b","type":"textarea","required":false},{"id":"party_b_title","token":"{{party_b_title}}","label":"Other Party Title","description":"Job title or role","category":"party_b","type":"text","required":false},{"id":"effective_date","token":"{{effective_date}}","label":"Effective Date","description":"When the agreement becomes effective","category":"dates","type":"date","required":true},{"id":"signature_date","token":"{{signature_date}}","label":"Signature Date","description":"Date of signing","category":"dates","type":"date","required":false},{"id":"governing_jurisdiction","token":"{{governing_jurisdiction}}","label":"Governing Jurisdiction","description":"State/country whose laws govern the agreement","category":"terms","type":"text","required":true},{"id":"notice_period","token":"{{notice_period}}","label":"Notice Period","description":"Days notice required for termination","category":"terms","type":"number","required":false},{"id":"investment_amount","token":"{{investment_amount}}","label":"Investment Amount","description":"Amount being invested","category":"financial","type":"currency","required":true},{"id":"discount_rate","token":"{{discount_rate}}","label":"Discount Rate","description":"Discount percentage for conversion","category":"financial","type":"number","required":false},{"id":"valuation_cap","token":"{{valuation_cap}}","label":"Valuation Cap","description":"Maximum valuation for conversion","category":"financial","type":"currency","required":false}]'::jsonb,
